function checkArithmeticSubarrays(nums, l, r) {
    const results = [];
    for(let i = 0; i < l.length; i++) {
        const subarray = nums.slice(l[i], r[i] + 1).sort((a, b) => a - b);
        let is_arithmetic = true;
        const diff = subarray[1] - subarray[0];
        for(let j = 1; j < subarray.length - 1; j++) {
            if(subarray[j + 1] - subarray[j] !== diff) {
                is_arithmetic = false;
                break;
            }
        }
        results.push(is_arithmetic);
    }
    return results;
}
```


    1. For each element `i` in arrays `l` and `r`, create a subarray from `nums` using the range `[l[i], r[i]]`.
2. Sort the subarray.
3. Check if the subarray is an arithmetic sequence, by iterating through the subarray and making sure the difference between consecutive elements is the same.
4. If the subarray is an arithmetic sequence, add `true` to the result array, otherwise, add `false`.
5. Repeat this process for all the elements in arrays `l` and `r`.
6. Return the results array containing the answers for each query.

